<script>
  // Sidebar collapse
  const edgeBtn = document.getElementById('edgeBtn');
  const sidebar = document.getElementById('sidebar');
  const main = document.getElementById('main');
  if (edgeBtn) {
    edgeBtn.addEventListener('click', () => {
      sidebar.classList.toggle('collapsed');
      main.classList.toggle('collapsed');
    });
  }

  // Menu active state + 保留連結跳轉
  const menuItems = document.querySelectorAll('.menu-item');
  menuItems.forEach(mi => {
    mi.addEventListener('click', (e) => {
      // 不阻止預設行為 → 讓連結可以跳轉
      menuItems.forEach(n => n.classList.remove('active'));
      mi.classList.add('active');
    });
  });

  // 點擊外部 → 關閉選單
  document.addEventListener('click', function (e) {
    if (!e.target.closest('.custom-select-wrapper')) {
      const langOptions = document.getElementById('langOptions');
      if (langOptions) {
        langOptions.style.display = 'none';
      }
    }
  });
</script>

<!-- Admin Select -->
<script>
  // Admin dropdown
  const adminBtn = document.getElementById('adminBtn');
  const adminMenu = document.getElementById('adminMenu');
  if (adminBtn && adminMenu) {
    adminBtn.addEventListener('click', () => {
      const open = adminMenu.style.display === 'block';
      adminMenu.style.display = open ? 'none' : 'block';
      adminMenu.setAttribute('aria-hidden', open ? 'true' : 'false');
    });
    document.addEventListener('click', (e) => {
      if (!e.target.closest('.admin-wrapper')) {
        adminMenu.style.display = 'none';
        adminMenu.setAttribute('aria-hidden', 'true');
      }
    });
  }
</script>

