  // 展開/收合語系選單
  document.getElementById('langTrigger').addEventListener('click', function () {
    const options = document.getElementById('langOptions');
    options.style.display = options.style.display === 'none' ? 'block' : 'none';
  });

  // 點選語系 → 更新按鈕文字 → 套用翻譯
  document.querySelectorAll('#langOptions li').forEach(function (item) {
    item.addEventListener('click', function () {
      const lang = item.getAttribute('data-locale');

      // 更新按鈕顯示文字
      document.querySelector('.lang-label').textContent = item.textContent;

      // 關閉選單
      document.getElementById('langOptions').style.display = 'none';

      // 套用翻譯
      document.querySelectorAll('[data-i18n]').forEach(el => {
        const key = el.getAttribute('data-i18n');
        if (translations[lang] && translations[lang][key]) {
          el.textContent = translations[lang][key];
        }
      });
    });
  });

</script>
